import React from 'react';
import { history } from 'umi';
import { observer, inject } from 'mobx-react';
import { toJS } from 'mobx';
import { Guide } from 'bizcharts';
import { errBoundary } from '@/components/ErrorBoundary';
import CompoundChart, { IGeom, enum_geom_type } from '@/components/CompoundChart';
import PieChart from '@/components/PieChart';
import { UIStore } from '@/store/UI';
import StatisticsStore, { IPriceItem, IBusinessData, initBusinessData } from '@/store/Statistics/typings';
import AnalysisStore, {
    enum_date_type,
    IOrderDODItem,
    IRevenueDODItem,
    initRevenueDODItem,
    IPositiveRateDODItem,
    initPositiveRateDODItem,
    IShareRateDODItem,
    initShareRateDODItem,
    IRepurchaseRateDODItem,
    initRepurchaseRateDODItem,
    enum_chart_type
} from '@/store/Analysis/typings';
import { formatDate, formatPreDay, removeEmpty, getSize } from '@/utils/method';
import { Layout } from 'antd';
import { CaretUpFilled, CaretDownFilled } from '@ant-design/icons';
import styles from './index.less';

interface IProps {
    analysisStore: AnalysisStore;
    statisticsStore: StatisticsStore;
    uiStore: UIStore;
}

interface IState {
    priceList: IPriceItem[]; // mock测试
    todayBusinessData: IBusinessData; // 今天运营数据
    monthBusinessData: IBusinessData; // 本月运营数据
    recentOrderDOD: IOrderDODItem[]; // 最近七天订单环比
    recentRevenueDOD: IRevenueDODItem[]; // 最近七天营收环比
    todayRevenueData: IRevenueDODItem; // 今日营收数据
    monthRevenueData: IRevenueDODItem; // 本月营收数据

    positiveRateData: IPositiveRateDODItem;
    positiveRateDOD: IPositiveRateDODItem[]; // 近30日好评率
    shareRateData: IShareRateDODItem;
    shareRateDOD: IShareRateDODItem[]; // 近30日分享率
    repurchaseRateData: IRepurchaseRateDODItem;
    repurchaseRateDOD: IRepurchaseRateDODItem[]; // 近30日复购率
}

const { Content, Header } = Layout;

@inject('analysisStore', 'statisticsStore', 'uiStore')
@observer
class Index extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            priceList: [],
            recentOrderDOD: [],
            recentRevenueDOD: [],
            positiveRateDOD: [],
            shareRateDOD: [],
            repurchaseRateDOD: [],

            todayBusinessData: initBusinessData,
            monthBusinessData: initBusinessData,
            todayRevenueData: initRevenueDODItem,
            monthRevenueData: initRevenueDODItem,
            positiveRateData: initPositiveRateDODItem,
            shareRateData: initShareRateDODItem,
            repurchaseRateData: initRepurchaseRateDODItem
        };
    }
    componentDidMount() {
        const _this = this;
        _this.initData();
    }
    componentWillUnmount() {
        window.onresize = null;
    }
    initData = async () => {
        const { analysisStore, statisticsStore, uiStore } = this.props;
        const {
            getOrderCountAnalysis,
            getRevenueAnalysis,
            getPositiveRateAnalysis,
            getShareRateAnalysis,
            getRepurchaseRateAnalysis
        } = analysisStore;
        const { getStationStatistics, getDefendStatistics, getBusinessStatistics } = statisticsStore;
        uiStore.openLoading();
        // 计算需要用到的时间节点
        const now = new Date();
        const day7DateStr = formatPreDay(now, 7); // 计算7天前的日期
        const day30DateStr = formatPreDay(now, 30); // 计算30天前的日期
        const nowStr = formatDate(now, 'YYYY-MM-DD');
        const nowMonth = formatDate(now, 'YYYY-MM-01'); // 通过获取 年月 + '-01' 来得到本月第一天的日期
        const result = await Promise.all([
            getStationStatistics(), // 0 获取站点统计数据
            getDefendStatistics(), // 1 获取维修统计数据
            getBusinessStatistics(nowStr, nowStr), // 2 获取今日运营数据
            getBusinessStatistics(nowMonth, nowStr), // 3 获取本月运营数据
            getOrderCountAnalysis({ startTime: day7DateStr, endTime: nowStr, type: enum_date_type.day }), // 4 获取最近七日订单环比
            getRevenueAnalysis({ startTime: day7DateStr, endTime: nowStr, type: enum_date_type.day }), // 5 获取最近七日营收环比
            getRevenueAnalysis({ startTime: nowMonth, endTime: nowStr, type: enum_date_type.month }), // 6 获取本月营收数据
            getPositiveRateAnalysis({ startTime: day30DateStr, endTime: nowStr, orderType: '0' }), // 7 获取本月运营数据
            getShareRateAnalysis({ startTime: day30DateStr, endTime: nowStr, type: 1 }), // 8 获取订单分享率
            getRepurchaseRateAnalysis({ startTime: day30DateStr, endTime: nowStr, type: 1 }) // 9 获取复购率
        ]);
        const { data: todayBusinessData } = result[2];
        const { data: monthBusinessData } = result[3];
        const { data: recentOrderDOD } = result[4];
        const { data: recentRevenueDOD } = result[5];
        const { data: recentRevenueMOM } = result[6];
        const { data: positiveRateDOD } = result[7];
        const { data: shareRateDOD } = result[8];
        const { data: repurchaseRateDOD } = result[9];

        const positiveRateData =
            positiveRateDOD && positiveRateDOD.length ? positiveRateDOD[positiveRateDOD.length - 1] : {};
        const shareRateData = shareRateDOD && shareRateDOD.length ? shareRateDOD[shareRateDOD.length - 1] : {};
        const repurchaseRateData =
            repurchaseRateDOD && repurchaseRateDOD.length ? repurchaseRateDOD[repurchaseRateDOD.length - 1] : {};
        this.setState(
            removeEmpty({
                todayBusinessData,
                monthBusinessData,
                recentOrderDOD,
                recentRevenueDOD,
                todayRevenueData: recentRevenueDOD?.slice(-1)[0] || initRevenueDODItem,
                monthRevenueData: recentRevenueMOM?.slice(-1)[0] || initRevenueDODItem,
                positiveRateData,
                positiveRateDOD,
                shareRateData,
                shareRateDOD,
                repurchaseRateData,
                repurchaseRateDOD
            })
        );
        // this.setState({ priceList: result.data });
        uiStore.closeLoading();
    };
    goToPage = (type: enum_chart_type) => () => {
        this.props.analysisStore.changeChartType(type);
        history.push('/analysis');
    };
    goToKanBan = () => {
        window.location.href = `${APP_CONFIG.MAPIC_CDN}kanban/index.html`;
    };

    render() {
        const _this = this;
        const {
            monthBusinessData,
            recentOrderDOD,
            todayBusinessData,
            recentRevenueDOD,
            todayRevenueData,
            monthRevenueData,
            positiveRateData,
            positiveRateDOD,
            shareRateData,
            shareRateDOD,
            repurchaseRateData,
            repurchaseRateDOD
        } = this.state;
        const { statisticsStore, uiStore } = this.props;
        const { stationStatistics, defendStatistics } = statisticsStore;
        const getGuideMarker = (data, xKeyName, yKeyName) => () => {
            if (data.length > 0) {
                // 只显示
                const newData = toJS(data);
                const length = newData.length;
                const position = [newData[length - 1][xKeyName], newData[length - 1][yKeyName]];
                return position; //位置信息
            }
        };
        // 配置折线的config
        const getLineConfig = (typeKey: string, typeName: string) => ({
            type: enum_geom_type.LINE,
            size: getSize(3),
            configList: [
                {
                    typeKey,
                    typeName,
                    color: '#f3a536'
                }
            ]
        });
        const getChartChildren = (data, xKeyName, yKeyName) => {
            return (
                <React.Fragment>
                    {data.length > 0 && (
                        <Guide>
                            <Guide.Region
                                start={['90%', '-20%']} // 辅助框起始位置，值为原始数据值，支持 callback
                                end={['110%', '120%']} // 辅助框结束位置，值为原始数据值，支持 callback
                                style={{
                                    lineWidth: 0, // 辅助框的边框宽度
                                    fill: '#eee', // 辅助框填充的颜色
                                    fillOpacity: 1 // 辅助框的背景透明度
                                }} // 辅助框的图形样式属性
                            />
                            <Guide.DataMarker
                                top // 指定 giude 是否绘制在 canvas 最上层，默认为 false, 即绘制在最下层
                                position={getGuideMarker(data, xKeyName, yKeyName)}
                                display={{
                                    point: true,
                                    line: false,
                                    text: false
                                }} //可选，是否显示文本/point/line，默认为全部显示
                                style={{
                                    point: {
                                        fill: '#f3a536',
                                        stroke: '#f3a536'
                                    }
                                }}
                            />
                        </Guide>
                    )}
                </React.Fragment>
            );
        };
        // 遍历生成 运营数据 图表
        const operationChartList = [
            {
                title: '今日单量',
                value: todayBusinessData?.totalNum,
                titleTip: `自营单量：${todayBusinessData?.autarkyTotalNum}`,
                leftFooter: `当月单量：${monthBusinessData?.totalNum}`,
                rightFooter: `成交率：${monthBusinessData?.successNum.toFixed(2)}%`,
                xKeyName: 'day',
                yKeyName: 'num',
                data: recentOrderDOD,
                geomList: [getLineConfig('num', '单量')],
                onClick: _this.goToPage(enum_chart_type.orderCount)
            },
            {
                title: '今日营业额',
                value: todayBusinessData?.realMoney,
                leftFooter: `当月营业额：${monthBusinessData?.realMoney}`,
                rightFooter: `当月客单：${(monthBusinessData?.realMoney / monthBusinessData?.totalNum || 0).toFixed(
                    2
                )}`,
                xKeyName: 'day',
                yKeyName: 'income',
                data: recentOrderDOD,
                geomList: [getLineConfig('income', '营业额')],
                onClick: _this.goToPage(enum_chart_type.revenue)
            },
            {
                title: '今日毛利',
                value: todayRevenueData?.grossProfit,
                leftFooter: `当月毛利：${monthRevenueData?.grossProfit}`,
                rightFooter: `完成率：${'--'}%`,
                xKeyName: 'f_indate',
                yKeyName: 'grossProfit',
                data: recentRevenueDOD,
                geomList: [getLineConfig('grossProfit', '毛利')],
                onClick: _this.goToPage(enum_chart_type.revenue)
            }
        ];
        // 遍历生成 反馈数据 图表
        const feedbackChartList = [
            {
                title: '近30日好评率(%)',
                value: positiveRateData?.positiveRate,
                xKeyName: 'f_indate',
                yKeyName: 'positiveRate',
                scale: {
                    positiveRate: { min: 0 }
                },
                data: (() => {
                    const newData = {};
                    positiveRateDOD.forEach((item: IPositiveRateDODItem) => {
                        if (newData[item.f_indate]) {
                            newData[item.f_indate].push(+item.positiveRate);
                        } else {
                            newData[item.f_indate] = [+item.positiveRate];
                        }
                    });
                    const data = Object.keys(newData).map(keyItem => ({
                        f_indate: keyItem,
                        positiveRate: +(
                            newData[keyItem].reduce((preTotal, curData) => preTotal + curData, 0) /
                            newData[keyItem].length
                        ).toFixed(2)
                    }));
                    return data;
                })(),
                geomList: [getLineConfig('positiveRate', '好评率')],
                onClick: _this.goToPage(enum_chart_type.positiveRate)
            },
            {
                title: '近30日分享率(%)',
                value: shareRateData?.share_rate,
                xKeyName: 'f_indate',
                yKeyName: 'share_rate',
                data: shareRateDOD,
                geomList: [getLineConfig('share_rate', '分享率')],
                onClick: _this.goToPage(enum_chart_type.shareRate)
            },
            {
                title: '近30日复购率(%)',
                value: repurchaseRateData?.repurchaseRate,
                xKeyName: 'f_indate',
                yKeyName: 'repurchaseRate',
                data: repurchaseRateDOD,
                geomList: [getLineConfig('repurchaseRate', '复购率')],
                onClick: _this.goToPage(enum_chart_type.repurchaseRate)
            }
        ];
        const getIcon = item => {
            const yesterday = +item.data.slice(-2, -1)[0][item.yKeyName];
            const today = +item.data.slice(-1)[0][item.yKeyName];
            return today - yesterday > 0 ? (
                <CaretUpFilled className={styles.caretUp} />
            ) : (
                <CaretDownFilled className={styles.caretDown} />
            );
        };
        const chartProps = item => ({
            padding: ['10%'],
            xConfig: { name: item.xKeyName, visible: false },
            yConfig: { name: item.yKeyName, visible: false },
            data: item.data,
            geomList: item.geomList,
            chartChildren: getChartChildren(item.data, item.xKeyName, item.yKeyName),
            ifCanClick: true
        });
        return (
            <div id="page-homepage">
                <Header className={styles.navHeader}>
                    <div className={styles.headerTitle}>{uiStore.navTitle}</div>
                    <div className={styles.headerRight} onClick={this.goToKanBan}>
                        地图
                    </div>
                </Header>
                <Content id="page-homepage" className={styles.container}>
                    <div className={styles.leftContainer}>
                        {/* 今日运营数据 */}
                        <div className={styles.operationCard}>
                            {operationChartList.map((item, index) => (
                                <div key={index} className={styles.chartCard} onClick={item.onClick}>
                                    <div className={styles.chartHeader}>
                                        <div className={styles.chartHeaderLeft}>
                                            <div className={styles.chartHeaderTitle}>{item.title}</div>
                                            <div className={styles.chartHeaderVal}>{item.value}</div>
                                        </div>
                                        <div className={styles.chartHeaderRight}>
                                            <div className={styles.chartHeaderTitle}>{item.titleTip}</div>
                                        </div>
                                    </div>
                                    <div id="page-homepage-operationChart" style={{ flex: 1 }}>
                                        <CompoundChart {...chartProps(item)} />
                                    </div>
                                    <div className={styles.chartFooter}>
                                        {item.leftFooter && <div>{item.leftFooter}</div>}
                                        {item.rightFooter && <div>{item.rightFooter}</div>}
                                    </div>
                                </div>
                            ))}
                        </div>
                        {/* 今日反馈数据 */}
                        <div className={styles.feedbackCard}>
                            {feedbackChartList.map((item, index) => (
                                <div key={index} className={styles.chartCard} onClick={item.onClick}>
                                    <div className={styles.chartHeader}>
                                        <div className={styles.headerTip}>
                                            <div className={styles.chartHeaderTitle}>{item.title}</div>
                                            <div className={styles.chartHeaderVal}>
                                                {item.value}
                                                {item.data.length > 1 && getIcon(item)}
                                            </div>
                                        </div>
                                    </div>
                                    <div id="page-homepage-feedbackChart" style={{ flex: 1 }}>
                                        <CompoundChart {...chartProps(item)} />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <div className={styles.rightContainer}>
                        {/* 站点统计 */}
                        <div className={styles.factoryCard}>
                            <div className={styles.header}>
                                <div className={styles.headerItem}>
                                    <div className={styles.headerTitle}>站点数量</div>
                                    <div className={styles.headerVal}>{stationStatistics.运营中}</div>
                                </div>
                                <div className={styles.headerItem}>
                                    <div className={styles.headerTitle}>维护中</div>
                                    <div className={styles.headerVal}>{stationStatistics.维护中}</div>
                                </div>
                                <div className={styles.headerItem}>
                                    <div className={styles.headerTitle}>运营率(%)</div>
                                    <div className={styles.headerVal}>
                                        {(
                                            100 - (stationStatistics.维护中 * 100) / stationStatistics.运营中 || 0
                                        ).toFixed(2)}
                                    </div>
                                </div>
                            </div>
                            <div className={styles.footer}>
                                <div className={styles.footerItem}>
                                    <div className={styles.footerTitle}>故障抢修</div>
                                    <div className={styles.footerVal}>{defendStatistics.alarmNum}</div>
                                </div>
                                <div className={styles.footerItem}>
                                    <div className={styles.footerTitle}>油站原因</div>
                                    <div className={styles.footerVal}>{defendStatistics.stationNum}</div>
                                </div>
                                <div className={styles.footerItem}>
                                    <div className={styles.footerTitle}>设备升级</div>
                                    <div className={styles.footerVal}>{defendStatistics.upgradingNum}</div>
                                </div>
                                <div className={styles.footerItem}>
                                    <div className={styles.footerTitle}>天气原因</div>
                                    <div className={styles.footerVal}>{defendStatistics.frostNum}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </Content>
            </div>
        );
    }
}

export default errBoundary(Index);
